/**
 * Validates that the input length does not exceed 60 characters.
 * @param {string} input - The user input to validate.
 * @return {boolean} Returns true if the input length is 60 or fewer characters, otherwise false.
 */
function validateInput(input) {
    //Convert to string always to prevent issue with only numbers
    input = String(input);
    const isValid = input.length <= 60; // Check if input length is within the limit
    return isValid;
}

